const body = $input.first().json;

const entry = body.entry?.[0] || {};
const messaging = entry.messaging?.[0];

if (!messaging || !messaging.message) {
  // Not a message event (could be delivery, read receipt, postback, etc.)
  return [{
    json: {
      is_message: false,
      event_type: messaging?.delivery ? 'delivery' : messaging?.read ? 'read' : 'other'
    }
  }];
}

const senderId = messaging.sender?.id || '';
const recipientId = messaging.recipient?.id || '';
const message = messaging.message || {};

// Detect if this is Instagram or Messenger
// Instagram messages have a different structure and may include
// 'instagram_business_account' in the entry or different ID formats
let channelType = 'messenger';

// Instagram DMs typically come with is_echo or through instagram-specific fields
if (entry.id && messaging.sender && messaging.recipient) {
  // Check for Instagram indicators
  if (body.object === 'instagram' || entry.messaging?.[0]?.sender?.id?.length > 20) {
    channelType = 'instagram';
  }
}

// Extract message content
let content = '';
let messageType = 'text';

if (message.text) {
  content = message.text;
  messageType = 'text';
} else if (message.attachments && message.attachments.length > 0) {
  const attachment = message.attachments[0];
  messageType = attachment.type || 'attachment';
  content = '[' + messageType + ']';
  if (attachment.payload?.url) {
    content += ' ' + attachment.payload.url;
  }
} else if (message.sticker_id) {
  content = '[Sticker]';
  messageType = 'sticker';
}

return [{
  json: {
    is_message: true,
    channel_type: channelType,
    platform_user_id: senderId,
    platform_message_id: message.mid || '',
    content: content,
    message_type: messageType,
    sender_name: '',
    page_id: recipientId,
    timestamp: messaging.timestamp || ''
  }
}];

const msg = $input.first().json;

const systemPrompt = [
  'You are a lead qualification AI for an educational institute that offers:',
  '- Professional courses: Data Analytics, Python, MERN, Web Dev, AI/ML, etc.',
  '- Academic tuition: BCA, BSCIT, ICT',
  '',
  'Analyze the lead/message and respond ONLY with valid JSON:',
  '{',
  '  "score": <number 1-10>,',
  '  "classification": "hot_lead" | "warm_lead" | "cold_lead" | "spam" | "not_a_lead",',
  '  "interest_type": "Professional" | "Academic" | "Unknown",',
  '  "course_interest": "<extracted course name or empty>",',
  '  "extracted_name": "<name if mentioned>",',
  '  "reason": "<brief explanation>",',
  '  "suggested_reply": "<brief friendly auto-reply in same language as message>"',
  '}',
  '',
  'Scoring guide:',
  '- 8-10: Clear course interest, real contact info, specific program mentioned',
  '- 5-7: General interest, vague details, might need follow-up',
  '- 3-4: Low quality, incomplete info, unclear intent',
  '- 1-2: Spam, test submission, or clearly not interested',
  '',
  'Note: Messages may be in Hindi, Gujarati, or English. Handle all languages.',
  'Never mention fees in suggested_reply.'
].join('\n');

const platform = msg.channel_type === 'instagram' ? 'Instagram DM' : 'Facebook Messenger';
const userMessage = platform + ' message from user ID: ' + msg.platform_user_id + '\nMessage: ' + msg.content;

return [{
  json: {
    ...msg,
    request_body: {
      model: 'llama-3.3-70b-versatile',
      temperature: 0.3,
      max_tokens: 500,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMessage }
      ]
    }
  }
}];

const response = $input.first().json;
const msg = $('Prepare AI Request').first().json;

let aiText = response.choices?.[0]?.message?.content || '';
aiText = aiText.replace(/```json|```/g, '').trim();

let ai;
try {
  ai = JSON.parse(aiText);
} catch (e) {
  ai = {
    score: 5,
    classification: 'warm_lead',
    interest_type: 'Unknown',
    course_interest: '',
    extracted_name: '',
    reason: 'AI parse error - defaulting to warm',
    suggested_reply: ''
  };
}

const score = Number(ai.score) || 5;
const isInstagram = msg.channel_type === 'instagram';

return [{
  json: {
    lead_payload: {
      action: 'create_lead',
      name: ai.extracted_name || '',
      source: isInstagram ? 'Instagram DM' : 'Messenger',
      channel_type: msg.channel_type,
      entry_type: isInstagram ? 'Instagram DM' : 'Messenger',
      platform_user_id: msg.platform_user_id,
      interest_type: ai.interest_type || 'Unknown',
      course_interest: ai.course_interest || '',
      notes: 'AI: ' + (ai.reason || ''),
      ai_score: score,
      ai_classification: ai.classification || 'warm_lead',
      source_detail: isInstagram ? 'Instagram DM Inbound' : 'Messenger Inbound'
    },
    message_payload: {
      action: 'create_message',
      platform_user_id: msg.platform_user_id,
      channel_type: msg.channel_type,
      direction: 'inbound',
      message_type: msg.message_type || 'text',
      content: msg.content,
      platform_message_id: msg.platform_message_id,
      sender_name: msg.sender_name || '',
      ai_score: score,
      ai_classification: ai.classification || 'warm_lead'
    },
    suggested_reply: ai.suggested_reply || '',
    ai_score: score,
    platform_user_id: msg.platform_user_id,
    channel_type: msg.channel_type,
    page_id: msg.page_id
  }
}];
